/// Float type
typedef khronos_float_t = ffi.Float;
typedef Dartkhronos_float_t = double;

/// Time types
///
/// These types can be used to represent a time interval in nanoseconds or
/// an absolute Unadjusted System Time.  Unadjusted System Time is the number
/// of nanoseconds since some arbitrary system event (e.g. since the last
/// time the system booted).  The Unadjusted System Time is an unsigned
/// 64 bit value that wraps back to 0 every 584 years.  Time intervals
/// may be either signed or unsigned.
typedef khronos_utime_nanoseconds_t = khronos_uint64_t;
typedef khronos_stime_nanoseconds_t = khronos_int64_t;

/// Enumerated boolean type
///
/// Values other than zero should be considered to be true.  Therefore
/// comparisons should not be made against KHRONOS_TRUE.
enum khronos_boolean_enum_t {
  KHRONOS_FALSE(0),
  KHRONOS_TRUE(1),
  KHRONOS_BOOLEAN_ENUM_FORCE_SIZE(2147483647);

  final int value;
  const khronos_boolean_enum_t(this.value);

  static khronos_boolean_enum_t fromValue(int value) => switch (value) {
    0 => KHRONOS_FALSE,
    1 => KHRONOS_TRUE,
    2147483647 => KHRONOS_BOOLEAN_ENUM_FORCE_SIZE,
    _ => throw ArgumentError(
      'Unknown value for khronos_boolean_enum_t: $value',
    ),
  };
}

